=<p class ="editor-paragraph">
,script type ="application/adaptivecard+json">
{
    "type": "AdaptiveCard",
    "$schema": "http://adaptivecards.io/schemas/adaptive-card.json",
    "version": "1.6",
    "body": [
        {
            "type": "TextBlock",
            "text": "Lead Gen Workflow n8n - Email Approval",
            "wrap": true,
