                            "text": "OPTION 2",
                            "wrap": true,
                            "horizontalAlignment": "Center",
                            "fontType": "Monospace",
                            "size": "Large"
                        }
                    ],
                    "style": "attention"
                }
            ]
        },
        {
            "type": "TextBlock",
            "text": "Please select one of the options above",
